module binary_search_comparator(  
    input [3:0] target,  
    input [3:0] index,  
    output reg found  
);  
    reg [3:0] obf_array [0:15];  
    initial begin  
        // Initialize the obf_array with some values for testing purposes  
        obf_array[0] = 4'b0000;  
        obf_array[1] = 4'b0001;  
        obf_array[2] = 4'b0010;  
        obf_array[3] = 4'b0011;  
        obf_array[4] = 4'b0100;  
        obf_array[5] = 4'b0101;  
        obf_array[6] = 4'b0110;  
        obf_array[7] = 4'b0111;  
        obf_array[8] = 4'b1000;  
        obf_array[9] = 4'b1001;  
        obf_array[10] = 4'b1010;  
        obf_array[11] = 4'b1011;  
        obf_array[12] = 4'b1100;  
        obf_array[13] = 4'b1101;  
        obf_array[14] = 4'b1110;  
        obf_array[15] = 4'b1111;  
    end  

    always @(*) begin  
        found = (obf_array[index] == target);  
    end  
endmodule
